// Use the signed URL directly — Claude fetches the file itself.
// This avoids all binary-data / filesystem-mode complexity in n8n.
const signedPath  = $('04 · HTTP · Create Signed URL').item.json.signedURL;
const fullUrl     = 'https://lsgtllwlgcleraokdyfe.supabase.co/storage/v1' + signedPath;
const mimeType    = $('03 · Set · Extract Storage Path').item.json.mime_type;
const isPdf       = mimeType === 'application/pdf';

// Claude supports source.type "url" for both images and documents.
const contentBlock = isPdf
  ? { type: 'document', source: { type: 'url', url: fullUrl } }
  : { type: 'image',    source: { type: 'url', url: fullUrl } };

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 1024,
  messages: [{
    role: 'user',
    content: [
      contentBlock,
      { type: 'text', text: 'You are looking at an insurance Certificate of Insurance (COI) document. Extract three fields from this document. Respond with ONLY a JSON object — no preamble, no markdown code fences, no explanation. The JSON must have exactly these three keys: "policy_number" (string, the insurance policy number; null if not visible), "carrier_name" (string, the insurance company that issued the policy, e.g. "Liberty Mutual" or "Travelers"; null if not visible), "expiration_date" (string in YYYY-MM-DD format, the policy expiration / end date; null if not visible). Be conservative — use null rather than guessing. If multiple policies are shown, return the values for the first general liability policy. Output JSON only.' }
    ]
  }]
};

return [{ json: { claudeBody: JSON.stringify(body) } }];

// Parse Claude's response — extract the JSON from its text content.
const response = $input.first().json;
const content = response.content && response.content[0] && response.content[0].text;

if (!content) {
  return [{ json: { extraction_successful: false, error: 'No content in Claude response' } }];
}

// Strip any markdown code fences in case Claude returned them.
const cleaned = content.trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { extraction_successful: false, error: 'Could not parse JSON: ' + e.message } }];
}

const policy_number = parsed.policy_number;
const carrier_name = parsed.carrier_name;
const expiration_date = parsed.expiration_date;

// Success requires at least policy_number AND expiration_date.
const extraction_successful = !!(policy_number && expiration_date);
if (!extraction_successful) {
  return [{ json: { extraction_successful: false, error: 'Required fields missing — policy_number=' + policy_number + ', expiration_date=' + expiration_date } }];
}

// Validate date format.
if (!/^\d{4}-\d{2}-\d{2}$/.test(expiration_date) || isNaN(Date.parse(expiration_date))) {
  return [{ json: { extraction_successful: false, error: 'Invalid expiration_date format: ' + expiration_date } }];
}

return [{ json: { extraction_successful: true, policy_number, carrier_name: carrier_name || null, expiration_date } }];

